(function corrigirCredoV30(){
  if(!Array.isArray(cateLessons) || !cateLessons[0]) return;
  const errado = /<p>\s*terceiro dia ressurgiu dos mortos; subiu aos céus, está sentado à mão\s*<\/p>/gi;
  const correto = "desceu aos infernos; ao terceiro dia ressurgiu dos mortos; subiu aos céus, está sentado à mão direita de Deus Padre todo-poderoso, donde há de vir a julgar os vivos e os mortos;";
  cateLessons[0].html = cateLessons[0].html.replace(errado, "");
  cateLessons[0].html = cateLessons[0].html.replace(/desceu aos infernos;\s*ao(?!\s*terceiro dia)/gi, correto);
  cateLessons[0].html = cateLessons[0].html.replace(/foi crucificado, morto e sepultado;\s*desceu aos infernos;\s*ao/gi, "foi crucificado, morto e sepultado; " + correto);
})();

