// V35 — Banco Interno IndexedDB + Backup e Restauração
const DB_NAME='ProjetoAguiaDB';
const DB_VERSION=35;
const DB_STORES=['state','backups','logs'];

function openAguiaDB(){
 return new Promise((resolve,reject)=>{
  const req=indexedDB.open(DB_NAME, DB_VERSION);
  req.onupgradeneeded=e=>{
   const db=e.target.result;
   DB_STORES.forEach(store=>{
    if(!db.objectStoreNames.contains(store)){
     db.createObjectStore(store,{keyPath:'id'});
    }
   });
  };
  req.onsuccess=()=>resolve(req.result);
  req.onerror=()=>reject(req.error);
 });
}

async function dbPut(store, value){
 const db=await openAguiaDB();
 return new Promise((resolve,reject)=>{
  const tx=db.transaction(store,'readwrite');
  tx.objectStore(store).put(value);
  tx.oncomplete=()=>resolve(true);
  tx.onerror=()=>reject(tx.error);
 });
}

async function dbGet(store, id){
 const db=await openAguiaDB();
 return new Promise((resolve,reject)=>{
  const tx=db.transaction(store,'readonly');
  const req=tx.objectStore(store).get(id);
  req.onsuccess=()=>resolve(req.result);
  req.onerror=()=>reject(req.error);
 });
}

async function dbGetAll(store){
 const db=await openAguiaDB();
 return new Promise((resolve,reject)=>{
  const tx=db.transaction(store,'readonly');
  const req=tx.objectStore(store).getAll();
  req.onsuccess=()=>resolve(req.result||[]);
  req.onerror=()=>reject(req.error);
 });
}

async function dbClear(store){
 const db=await openAguiaDB();
 return new Promise((resolve,reject)=>{
  const tx=db.transaction(store,'readwrite');
  tx.objectStore(store).clear();
  tx.oncomplete=()=>resolve(true);
  tx.onerror=()=>reject(tx.error);
 });
}

async function dbLog(message){
 try{
  await dbPut('logs',{id:'log-'+Date.now(),date:new Date().toISOString(),message});
 }catch(e){}
}

async function saveToDB(reason='auto'){
 try{
  await dbPut('state',{id:'current',version:35.2,updatedAt:new Date().toISOString(),reason,state});
  localStorage.setItem('aguiaV35_lastSync', new Date().toISOString());
  await dbLog('Estado salvo: '+reason);
  renderBackupStatus();
 }catch(e){
  console.warn('Erro ao salvar no IndexedDB', e);
 }
}

const originalSaveV35 = save;
save = function(){
 originalSaveV35();
 saveToDB('alteração automática');
};

async function migrateLocalStorageToDB(){
 try{
  await dbPut('state',{id:'current',version:35.2,migratedAt:new Date().toISOString(),state});
  await dbLog('Migração localStorage -> IndexedDB concluída.');
  localStorage.setItem('aguiaV35_migrated','yes');
  renderBackupStatus();
  return true;
 }catch(e){
  console.error(e);
  return false;
 }
}

async function loadFromDBIfAvailable(){
 try{
  const current=await dbGet('state','current');
  if(current && current.state && !localStorage.getItem('aguiaV35_loadedFromDB')){
   state=current.state;
   localStorage.setItem('aguiaV35_loadedFromDB','yes');
   originalSaveV35();
  }
 }catch(e){}
}

function buildBackupPayload(){
 return {
  app:'Projeto Águia',
  version:35.2,
  exportedAt:new Date().toISOString(),
  state:state,
  meta:{
   xp:state.xp||0,
   catechismDone:Object.keys(state.cateDone||{}).length,
   missionsApproved:Object.values(state.money||{}).filter(v=>Number(v)>0).length,
   academySubjects:Object.keys(state.academyStats||{}).length
  }
 };
}

async function exportBackupJSON(){
 const payload=buildBackupPayload();
 await dbPut('backups',{id:'last',createdAt:payload.exportedAt,payload});
 await dbPut('backups',{id:'backup-'+Date.now(),createdAt:payload.exportedAt,payload});
 localStorage.setItem('aguiaV35_lastBackup', payload.exportedAt);
 const blob=new Blob([JSON.stringify(payload,null,2)],{type:'application/json'});
 const a=document.createElement('a');
 const date=new Date().toISOString().slice(0,10);
 a.href=URL.createObjectURL(blob);
 a.download=`Projeto_Aguia_Backup_V35_${date}.json`;
 a.click();
 renderBackupStatus();
}

async function importBackupJSON(file){
 const text=await file.text();
 const payload=JSON.parse(text);
 if(!payload.state) throw new Error('Backup inválido: campo state ausente.');
 state=payload.state;
 originalSaveV35();
 await dbPut('state',{id:'current',version:35.2,importedAt:new Date().toISOString(),state});
 await dbPut('backups',{id:'last',createdAt:new Date().toISOString(),payload});
 localStorage.setItem('aguiaV35_lastBackup', new Date().toISOString());
 renderAll();
 renderBackupStatus();
}

async function restoreLastBackup(){
 const backup=await dbGet('backups','last');
 if(!backup || !backup.payload || !backup.payload.state){
  alert('Nenhum backup encontrado.');
  return;
 }
 state=backup.payload.state;
 originalSaveV35();
 await dbPut('state',{id:'current',version:35.2,restoredAt:new Date().toISOString(),state});
 renderAll();
 renderBackupStatus();
 alert('Backup restaurado.');
}

async function clearAguiaDB(){
 if(!confirm('Tem certeza que deseja limpar o banco interno? O localStorage atual será mantido.')) return;
 await dbClear('state');
 await dbClear('backups');
 await dbClear('logs');
 localStorage.removeItem('aguiaV35_lastBackup');
 renderBackupStatus();
 alert('Banco interno limpo.');
}

async function renderBackupStatus(){
 const status=document.getElementById('dbStatus');
 if(!status) return;
 try{
  const current=await dbGet('state','current');
  const backups=await dbGetAll('backups');
  const logs=await dbGetAll('logs');
  const last=localStorage.getItem('aguiaV35_lastBackup') || (backups.find(b=>b.id==='last')||{}).createdAt || 'Nunca';
  status.className='details ok';
  status.innerHTML='🟢 Banco IndexedDB ativo e sincronizado.';
  const br=document.getElementById('backupRecords'); if(br) br.textContent=String(backups.length + logs.length + (current?1:0));
  const lb=document.getElementById('lastBackup'); if(lb) lb.textContent=last==='Nunca'?'Nunca':new Date(last).toLocaleString();
  const dh=document.getElementById('dbHealth'); if(dh) dh.textContent=current?'Sincronizado':'Aguardando';
  const bv=document.getElementById('backupVersion'); if(bv) bv.textContent='V35';
  const log=document.getElementById('backupLog');
  if(log) log.textContent='Últimas ações:\n'+logs.slice(-5).reverse().map(l=>`• ${new Date(l.date).toLocaleString()}: ${l.message}`).join('\n');
 }catch(e){
  status.className='details warn';
  status.innerHTML='🟡 IndexedDB indisponível neste navegador ou sessão.';
 }
}

document.addEventListener('change',e=>{
 if(e.target && e.target.id==='importBackupFile'){
  const file=e.target.files && e.target.files[0];
  if(file){
   importBackupJSON(file).then(()=>alert('Backup importado com sucesso.')).catch(err=>alert('Erro ao importar backup: '+err.message));
  }
 }
});

document.addEventListener('click',e=>{
 if(!e.target) return;
 if(e.target.id==='exportBackup') exportBackupJSON();
 if(e.target.id==='restoreLastBackup') restoreLastBackup();
 if(e.target.id==='migrateToDB') migrateLocalStorageToDB().then(ok=>alert(ok?'Dados migrados para IndexedDB.':'Falha na migração.'));
 if(e.target.id==='clearDB') clearAguiaDB();
});

setTimeout(()=>{
 migrateLocalStorageToDB();
 renderBackupStatus();
},500);

function iso(d){return d.toISOString().slice(0,10)} function today(){return iso(new Date())} function money(n){return 'R$ '+Number(n).toFixed(0)} function plan(d){return plans[d.getDay()]} function tid(d,i){return iso(d)+'-'+i}
function stats(d=new Date()){let p=plan(d),done=0;p[3].forEach((_,i)=>{if(state.checked[tid(d,i)])done++});return{done,total:p[3].length,pct:Math.round(done/p[3].length*100),complete:done===p[3].length}}
function avg(arr){return arr.reduce((a,b)=>a+Number(b||0),0)/4}
function criticalSubject(){return Object.entries(state.grades||defaultGrades).map(([s,arr])=>[s,avg(arr)]).sort((a,b)=>a[1]-b[1])[0][0]}
function weakAcademySubject(){let rows=Object.entries(state.academyStats||{}).filter(([s,v])=>(v.total||0)>0).map(([s,v])=>[s,(v.correct||0)/(v.total||1)]); if(!rows.length) return null; return rows.sort((a,b)=>a[1]-b[1])[0][0];}
function smartPriority(){let c=criticalSubject(); if(questionBank[c]) return c; return weakAcademySubject() || 'Matemática';}
function weekMoneyTotal(){return Object.values(state.money).reduce((a,b)=>a+b,0)}
function switchTab(tab){document.querySelectorAll('.panel').forEach(p=>p.classList.remove('active'));document.getElementById(tab).classList.add('active');document.querySelectorAll('[data-tab]').forEach(b=>b.classList.toggle('active',b.dataset.tab===tab));renderAll()}
enter.onclick=()=>{if(pass.value===PASSWORD){localStorage.setItem('unlockedV23','yes');lock.classList.add('hidden');app.classList.remove('hidden');switchTab('journey')}else alert('Senha incorreta')};if(localStorage.getItem('unlockedV23')==='yes'){lock.classList.add('hidden');app.classList.remove('hidden');setTimeout(()=>switchTab('journey'),0)}
function saturdaysOfYear(){let y=new Date().getFullYear(),d=new Date(y,0,1),arr=[];while(d.getFullYear()===y){if(d.getDay()===6)arr.push(new Date(d));d.setDate(d.getDate()+1)}return arr.slice(0,52)}
function cateWeekIndex(date=new Date()){let sats=saturdaysOfYear();let idx=sats.findIndex(s=>iso(s)>=iso(date));return idx<0?51:idx}
function cateDoneCount(){return Object.keys(state.cateDone).length}

function approvedMissionCount(){
 return Object.values(state.money || {}).filter(v => Number(v) > 0).length;
}
function completedTaskCount(){
 return Object.values(state.checked || {}).filter(Boolean).length;
}
function missionProgressScore(){
 const approved = approvedMissionCount();
 const tasks = completedTaskCount();
 return { approved, tasks };
}

function renderMission(){let d=new Date(),p=plan(d),s=stats(d);todayTitle.textContent=p[0]+' — '+p[1];tasks.innerHTML=p[3].map((t,i)=>`<label class="task"><input type="checkbox" data-id="${tid(d,i)}" ${state.checked[tid(d,i)]?'checked':''}><span><b>${t[0]}</b><small>${t[1]}</small></span></label>`).join('');dayPct.textContent=s.pct+'%';dayBar.style.width=s.pct+'%';todayMoney.textContent=state.money[today()]?money(10):'R$ 0';missionText.textContent=s.complete?'Missão completa. Peça aprovação.':'Complete tudo para liberar R$ 10.';tasksDone.textContent=s.done+'/'+s.total}
function renderEagleMessage(){let s=stats(),p=plan(new Date());eagleMessage.textContent=`Prioridade atual: ${smartPriority()}. Hoje é dia de ${p[1]}. Faltam ${Math.max(0,s.total-s.done)} tarefa(s).`}
function buildKnowledge(){return `Projeto Águia V35.2.5\nNotas: ${JSON.stringify(state.grades)}\nPrioridade: ${smartPriority()}\nDesempenho academia: ${JSON.stringify(state.academyStats)}\nCatecismo: ${cateDoneCount()}/52\nXP: ${state.xp}`;}
function generateAIPlan(){let pr=smartPriority();state.aiPlan=`${buildKnowledge()}\n\nCrie um plano curto para hoje priorizando ${pr} e inclua 3 exercícios.`;save()}
function renderAI(){if(!state.aiPlan)generateAIPlan();aiPrompt.value=state.aiPlan;critical.textContent=smartPriority()}
function localAI(q){q=(q||'').toLowerCase();let c=smartPriority();if(aiMode.value==='online')return 'Modo online: copie a base de conhecimento e cole em uma IA externa. Para API real, use backend seguro.';if(q.includes('nota')||q.includes('boletim'))return `As notas estão sincronizadas com o responsável. Prioridade atual: ${c}.`;if(q.includes('academia'))return `Na Academia, recomendo responder perguntas de ${c} primeiro. O app evita repetir questões já vistas.`;return `Minha recomendação: comece por ${c}, responda 3 perguntas da Academia e revise seus erros.`}
function renderChallenge(){showQuestion(smartPriority(), challenge)}
function pickQuestion(sub){let bank=questionBank[sub]||[];state.seenQuestions[sub]=state.seenQuestions[sub]||[];let unseen=bank.map((_,i)=>i).filter(i=>!state.seenQuestions[sub].includes(i));if(unseen.length===0){state.seenQuestions[sub]=[];unseen=bank.map((_,i)=>i)}let idx=unseen[Math.floor(Math.random()*unseen.length)];state.seenQuestions[sub].push(idx);save();return {q:bank[idx],idx}}
function showQuestion(sub,target){state.selectedSubject=sub;save();target=target||quiz;let picked=pickQuestion(sub),q=picked.q;if(!q)return;target.innerHTML=`<h3>${icons[sub]||'📚'} ${sub}</h3><p><b>Pergunta nova:</b> ${q[0]}</p><small>Tema: ${q[4]||'Geral'}</small>`+q[1].map((a,i)=>`<button class="answer" data-sub="${sub}" data-qi="${picked.idx}" data-i="${i}">${a}</button>`).join('')+`<div class="feedback hidden"></div>`}
function renderAnnual(){let y=new Date().getFullYear();let names=['Janeiro','Fevereiro','Março','Abril','Maio','Junho','Julho','Agosto','Setembro','Outubro','Novembro','Dezembro'];annualCalendar.innerHTML=`<div class="annual-grid">`+names.map((name,m)=>{let first=new Date(y,m,1),last=new Date(y,m+1,0);let heads=['D','S','T','Q','Q','S','S'].map(x=>`<div class="head">${x}</div>`).join('');let cells='';for(let i=0;i<first.getDay();i++)cells+='<button class="mini-day empty"></button>';for(let day=1;day<=last.getDate();day++){let d=new Date(y,m,day),p=plan(d),key=iso(d),done=state.cateDone[key]?' ✅':'';cells+=`<button class="mini-day ${p[2]}" data-annual="${key}">${day}${done}</button>`}return `<div class="month-card"><h3>${name}</h3><div class="mini-grid">${heads}${cells}</div></div>`}).join('')+`</div>`}
function describeDate(key){
 let d=new Date(key+'T00:00:00'),p=plan(d),idx=saturdaysOfYear().findIndex(x=>iso(x)===key);
 let pr=smartPriority();
 let extra=d.getDay()===6?`<br><b>✝️ Catecismo:</b> Lição ${idx+1}<br><button data-open-date-cate="${key}">Abrir lição</button>`:'';
 annualDetails.innerHTML=`<b>${p[0]} — ${key}</b><br>
 <small>Eixo: ${p[1]}</small><br><br>
 <b>Disciplinas do dia:</b><ul>${p[3].map(t=>`<li><b>${t[0]}</b>: ${t[1]}</li>`).join('')}</ul>
 <b>Conteúdos previstos:</b><br>${(curriculum[pr]||['Revisão geral']).join(' • ')}<br><br>
 <b>Exercícios recomendados:</b><br>Responder perguntas da Academia em ${pr}.<br><br>
 <b>Reforço por boletim:</b><br>Prioridade atual: ${pr}.${extra}`;
}
function renderCateReader(){let i=state.catePage||0,l=cateLessons[i],sats=saturdaysOfYear(),key=iso(sats[i]);let fav=state.cateFavorites.includes(i);cateReader.innerHTML=`<div class="reader"><h3>Lição ${i+1}: ${l.theme}</h3><small>Sábado: ${key} • bloco: ${l.range}</small><div class="reader-body">${l.html}</div><div class="reader-controls"><button id="prevCate" class="secondary">◀ Anterior</button><button id="nextCate">Próxima ▶</button><button id="favCate" class="secondary">${fav?'★ Remover favorito':'☆ Favoritar'}</button><button id="markCate">☑ Concluir leitura</button></div></div>`}
function renderCatechism(){let done=cateDoneCount(),pct=Math.round(done/52*100);cateProgress.textContent=pct+'%';cateDone.textContent=done+'/52';cateXP.textContent=state.cateXP+' XP';cateBar.style.width=pct+'%';cateMedal.textContent=done>=52?'Águia da Fé':done>=25?'Discípulo de São Pio X':done>=10?'Pequeno Catequista':'Primeiro Sábado';renderCateReader();renderCateSearch();renderCateFavorites();let current=state.catePage||cateWeekIndex();cateSchedule.innerHTML=saturdaysOfYear().map((d,i)=>`<div class="cate-week ${state.cateDone[iso(d)]?'done':''} ${i===current?'current':''}"><b>Lição ${i+1} — ${iso(d)}</b><br><small>${cateLessons[i].theme}</small><br><button data-open-cate="${i}">Abrir lição</button></div>`).join('');parentCatechism.innerHTML=`<div class="details"><b>${done}/52 sábados</b><br><small>${pct}% concluído • ${state.cateXP} XP</small></div>`}
function renderCateSearch(){let q=(cateSearch.value||'').toLowerCase();if(!q){cateSearchResults.innerHTML='<p class="muted">Digite uma palavra para buscar.</p>';return}let results=cateLessons.map((l,i)=>({t:l.theme,html:l.html,i})).filter(x=>x.t.toLowerCase().includes(q)||x.html.toLowerCase().includes(q));cateSearchResults.innerHTML=results.slice(0,20).map(r=>`<div class="search-result"><b>Lição ${r.i+1}: ${r.t}</b><br><button data-open-cate="${r.i}">Abrir</button></div>`).join('')||'<p class="muted">Nenhum resultado.</p>'}
function renderCateFavorites(){cateFavorites.innerHTML=state.cateFavorites.length?state.cateFavorites.map(i=>`<div class="favorite"><b>Lição ${i+1}: ${cateLessons[i].theme}</b><br><button data-open-cate="${i}">Abrir</button></div>`).join(''):'<p class="muted">Nenhum favorito ainda.</p>'}
function studyPercent(sub){
 let v=state.academyStats[sub]||{correct:0,total:0};
 let score=v.total?Math.round((v.correct/v.total)*100):0;
 let grade=state.grades[sub]?Math.round(avg(state.grades[sub])*10):50;
 return Math.max(10, Math.min(100, Math.round((score+grade)/2)));
}


function shuffleArray(arr){return [...arr].sort(()=>Math.random()-0.5)}
function getQuestionDifficulty(q){return (q[5]||'facil').toLowerCase()}
function startAcademySession(){
 const sub=(document.getElementById('disciplineSelect')?.value)||state.selectedSubject||smartPriority();
 const count=Number(document.getElementById('questionCountSelect')?.value||10);
 const difficulty=(document.getElementById('difficultySelect')?.value)||'misto';
 let pool=(questionBank[sub]||[]).map((q,i)=>({q,i}));
 if(difficulty!=='misto') pool=pool.filter(x=>getQuestionDifficulty(x.q)===difficulty);
 if(!pool.length){
   alert('Não há perguntas disponíveis para essa disciplina e dificuldade.');
   return;
 }
 const selected=shuffleArray(pool).slice(0,Math.min(count,pool.length));
 state.selectedSubject=sub;
 state.academySession={
   id:'session-'+Date.now(),
   date:today(),
   subject:sub,
   requested:count,
   difficulty,
   questions:selected.map(x=>x.i),
   current:0,
   correct:0,
   total:selected.length,
   answered:[]
 };
 save();
 renderAcademySession();
}
function renderAcademySession(){
 const box=document.getElementById('academySessionStatus');
 if(!box) return;
 const s=state.academySession;
 if(!s){
   box.innerHTML='<b>Academia V35.2.4 Recuperada:</b> escolha disciplina, quantidade e dificuldade para iniciar um treino.';
   return;
 }
 const sub=s.subject, bank=questionBank[sub]||[];
 if(s.current>=s.questions.length){
   const pct=s.total?Math.round((s.correct/s.total)*100):0;
   const xpGain=s.correct*5;
   box.innerHTML=`<b>Treino concluído!</b><br>${icons[sub]||'📚'} ${sub}<br><b>${s.correct}/${s.total}</b> acertos • ${pct}% • +${xpGain} XP`;
   quiz.innerHTML=`<div class="details"><b>Resultado final</b><br>Disciplina: ${sub}<br>Quantidade: ${s.total}<br>Acertos: ${s.correct}<br>Erros: ${s.total-s.correct}<br>XP conquistado: ${xpGain}</div><button id="startAcademySession">Novo treino</button>`;
   return;
 }
 const idx=s.questions[s.current], q=bank[idx];
 box.innerHTML=`<b>Treino em andamento:</b> ${icons[sub]||'📚'} ${sub}<br>Questão ${s.current+1}/${s.total} • Acertos: ${s.correct}`;
 quiz.innerHTML=`<h3>${icons[sub]||'📚'} ${sub}</h3>
 <p><b>Questão ${s.current+1}:</b> ${q[0]}</p>
 <small>Tema: ${q[4]||'Geral'} • Nível: ${q[5]||'facil'}</small>
 ${q[1].map((a,i)=>`<button class="answer-session" data-i="${i}">${a}</button>`).join('')}
 <div class="feedback hidden"></div>`;
}
function answerAcademySession(choice){
 const s=state.academySession;
 if(!s) return;
 const bank=questionBank[s.subject]||[], idx=s.questions[s.current], q=bank[idx];
 const ok=Number(choice)===q[2];
 if(ok){s.correct++;state.xp+=5}
 s.answered.push({questionId:q[6]||idx,choice:Number(choice),correct:ok});
 state.academyStats[s.subject]=state.academyStats[s.subject]||{correct:0,total:0};
 state.academyStats[s.subject].total++;
 if(ok) state.academyStats[s.subject].correct++;
 s.current++;
 if(s.current>=s.questions.length){
   state.academyHistory=state.academyHistory||[];
   state.academyHistory.unshift({id:s.id,date:s.date,subject:s.subject,total:s.total,correct:s.correct,difficulty:s.difficulty,xp:s.correct*5});
   state.academyHistory=state.academyHistory.slice(0,100);
 }
 save();
 renderAcademySession();
 renderAcademyStats();
}

function renderAcademy(){
 let pr=smartPriority();
 let selected=state.selectedSubject || pr;
 academyPriority.innerHTML=`<b>Prioridade inteligente:</b> ${icons[pr]||'📚'} ${pr}<br><small>Recomendação da Águia: hoje seria interessante estudar ${pr}. Mas João Miguel pode trocar e escolher qualquer disciplina.</small>`;
 if(document.getElementById('disciplineSelect')){
   disciplineSelect.innerHTML=subjectNames.map(s=>`<option value="${s}" ${s===selected?'selected':''}>${icons[s]||'📚'} ${s} (${(questionBank[s]||[]).length})</option>`).join('');
 }
 document.getElementById('curriculum').innerHTML=Object.entries(curriculum).map(([s,it])=>`<div class="item"><b>${icons[s]||'📚'} ${s}</b><br><small>${it.join(' • ')}</small></div>`).join('');
 document.getElementById('subjects').innerHTML=subjectNames.map(s=>`<button class="subject ${s===pr?'priority':''}" data-subject="${s}">${icons[s]||'📚'} ${s}</button>`).join('');
 let bars=subjectNames.map(s=>{let p=studyPercent(s);return `<div class="study-row"><b>${icons[s]||'📚'} ${s}</b><div class="study-meter"><span style="width:${p}%"></span></div><small>${p}%</small></div>`}).join('');
 academyPriority.innerHTML += `<div class="study-bars">${bars}</div>`;
 renderAcademySession();
 renderAcademyStats()
}

function normalizeGrade(x){x=String(x).replace(',','.');let n=parseFloat(x);if(isNaN(n))return null;if(n>10&&n<=100)n=n/10;return Math.max(0,Math.min(10,n))}
function parseGradesFromText(text){let found={};let norm=text.normalize('NFD').replace(/[\u0300-\u036f]/g,'').toLowerCase();for(let [alias,sub] of Object.entries(aliases)){let a=alias.normalize('NFD').replace(/[\u0300-\u036f]/g,'').toLowerCase();let idx=norm.indexOf(a);if(idx>=0){let slice=text.slice(Math.max(0,idx-20),idx+180);let nums=[...slice.matchAll(/\b(10(?:[,.]0)?|[0-9](?:[,.][0-9])?)\b/g)].map(m=>normalizeGrade(m[1])).filter(v=>v!==null);if(nums.length)found[sub]=nums.slice(0,4)}}return found}
function applyDetectedGrades(found){let count=0;for(let [s,nums] of Object.entries(found)){if(!state.grades[s])state.grades[s]=[0,0,0,0];for(let i=0;i<Math.min(4,nums.length);i++){state.grades[s][i]=nums[i];count++}}save();renderGradesTable();return count}
function renderGradesTable(){let b=['1º bim.','2º bim.','3º bim.','4º bim.'];gradesTable.innerHTML=`<table class="grade-table"><thead><tr><th>Disciplina</th>${b.map(x=>`<th>${x}</th>`).join('')}<th>Média</th></tr></thead><tbody>`+Object.entries(state.grades).map(([sub,arr])=>`<tr><td><b>${sub}</b></td>${[0,1,2,3].map(i=>`<td><input data-grade-sub="${sub}" data-grade-i="${i}" type="number" min="0" max="10" step="0.1" value="${arr[i]||0}"></td>`).join('')}<td><b>${avg(arr).toFixed(1)}</b></td></tr>`).join('')+`</tbody></table>`;renderParentGrades();renderAcademy()}
function renderParentGrades(){parentGradesTable.innerHTML=`<table class="grade-table"><thead><tr><th>Disciplina</th><th>1º</th><th>2º</th><th>3º</th><th>4º</th><th>Média</th></tr></thead><tbody>`+Object.entries(state.grades).map(([s,arr])=>`<tr><td><b>${s}</b></td>${arr.map(n=>`<td>${Number(n||0).toFixed(1)}</td>`).join('')}<td><b>${avg(arr).toFixed(1)}</b></td></tr>`).join('')+`</tbody></table>`}
function renderAcademyStats(){let html=subjectNames.map(s=>{let v=state.academyStats[s]||{correct:0,total:0};let pct=v.total?Math.round(v.correct/v.total*100):0;return `<div class="stat-card"><b>${icons[s]||'📚'} ${s}</b><br><small>${v.correct}/${v.total} acertos • ${pct}%</small></div>`}).join('');let hist=(state.academyHistory||[]).slice(0,10).map(h=>`<div class="history-row"><b>${h.date}</b> — ${h.subject}: ${h.correct}/${h.total} • +${h.xp} XP</div>`).join('')||'<p class="muted">Nenhum treino registrado ainda.</p>';academyStats.innerHTML=`<div class="grid">${html}</div><h3>Histórico recente</h3>${hist}`;parentAcademyStats.innerHTML=`<div class="grid">${html}</div>${hist}`}
function renderAchievements(){
 const achievementEl=document.getElementById('achievementList');
 const campaignEl=document.getElementById('campaignMap');
 const summaryEl=document.getElementById('achievementSummary');
 const levelEl=document.getElementById('journeyLevel');
 if(!achievementEl || !campaignEl) return;

 const approved=approvedMissionCount();
 const tasks=completedTaskCount();
 const cateDone=cateDoneCount();
 const xpVal=Number(state.xp || 0);

 const achievements=[
  {name:'🥉 Primeira missão', done:approved>=1, need:'Aprovar a primeira missão com o responsável.', progress:approved>=1?100:0, detail:`${approved} missão(ões) aprovada(s).`},
  {name:'🎯 Missionário da Semana', done:approved>=5, need:'Aprovar 5 missões.', progress:Math.min(100, Math.round(approved/5*100)), detail:`${approved}/5 missões aprovadas.`},
  {name:'✝️ Primeiro Sábado', done:cateDone>=1, need:'Concluir a primeira lição do Catecismo.', progress:Math.min(100, cateDone*100), detail:`${cateDone} sábado(s) concluído(s).`},
  {name:'📖 Pequeno Catequista', done:cateDone>=10, need:'Concluir 10 sábados.', progress:Math.min(100, Math.round(cateDone/10*100)), detail:`${cateDone}/10 sábados.`},
  {name:'🏛 Discípulo de São Pio X', done:cateDone>=25, need:'Concluir 25 sábados.', progress:Math.min(100, Math.round(cateDone/25*100)), detail:`${cateDone}/25 sábados.`},
  {name:'🦅 Águia da Fé', done:cateDone>=52, need:'Concluir 52 sábados.', progress:Math.min(100, Math.round(cateDone/52*100)), detail:`${cateDone}/52 sábados.`}
 ];

 const unlocked=achievements.filter(a=>a.done).length;
 const total=achievements.length;
 const pct=Math.round(unlocked/total*100);

 if(summaryEl){
  summaryEl.innerHTML=`
   <div class="achievement-summary">
    <b>Progresso das conquistas: ${unlocked}/${total}</b>
    <div class="progress-line"><span style="width:${pct}%"></span></div>
    <small>${pct}% das conquistas principais desbloqueadas.</small><br>
    <small>Missões aprovadas: <b>${approved}</b> • Tarefas concluídas: <b>${tasks}</b> • Catecismo: <b>${cateDone}/52</b> • XP: <b>${xpVal}</b></small>
   </div>
  `;
 }

 achievementEl.innerHTML=achievements.map(a=>`
  <div class="achievement ${a.done?'done':'locked'}">
   <b>${a.name}</b><br>
   <small>${a.done?'Desbloqueada':('Falta: '+a.need)}</small><br>
   <small>${a.detail}</small>
   <div class="progress-line"><span style="width:${a.progress}%"></span></div>
   <small>${a.progress}%</small>
  </div>
 `).join('');

 const levels=[
  {name:'Aspirante', xp:0, note:'Começo da jornada.'},
  {name:'Escudeiro', xp:50, note:'Primeiros hábitos firmes.'},
  {name:'Estudioso', xp:100, note:'Constância nos estudos.'},
  {name:'Discípulo', xp:150, note:'Estudo com disciplina.'},
  {name:'Águia Jovem', xp:200, note:'Autonomia crescente.'},
  {name:'Guardião', xp:250, note:'Perseverança e responsabilidade.'},
  {name:'Águia Imperial', xp:300, note:'Excelência na jornada.'}
 ];

 let currentIndex=0;
 for(let i=0;i<levels.length;i++){
  if(xpVal>=levels[i].xp) currentIndex=i;
 }

 const current=levels[currentIndex];
 const next=levels[currentIndex+1];
 const nextPct=next?Math.min(100, Math.max(0, Math.round((xpVal-current.xp)/(next.xp-current.xp)*100))):100;

 if(levelEl){
  levelEl.innerHTML=`
   <div class="journey-level-card">
    <div>🦅 Nível atual</div>
    <div class="level-name">${currentIndex+1}. ${current.name}</div>
    <small>${current.note}</small><br>
    <small>${xpVal} XP acumulados</small>
    <div class="progress-line"><span style="width:${nextPct}%"></span></div>
    <div class="next-goal">${next?`Próximo nível: <b>${next.name}</b> — faltam ${Math.max(0,next.xp-xpVal)} XP.`:'Nível máximo alcançado.'}</div>
   </div>
  `;
 }

 campaignEl.innerHTML=levels.map((l,i)=>{
  const unlocked=xpVal>=l.xp;
  const currentClass=i===currentIndex?'current':'';
  const prevXp=i===0?0:levels[i-1].xp;
  const localProgress=unlocked?100:Math.max(0, Math.min(100, Math.round((xpVal-prevXp)/(l.xp-prevXp)*100)));
  return `
   <div class="campaign-step ${unlocked?'done':'locked'} ${currentClass}">
    <b>${i+1}. ${l.name}</b><br>
    <small>${unlocked?'Desbloqueado com '+l.xp+' XP':'Desbloqueia com '+l.xp+' XP'}</small>
    <div class="progress-line"><span style="width:${localProgress}%"></span></div>
    <small>${unlocked?'100':localProgress}%</small>
   </div>
  `;
 }).join('');
}
function renderJourney(){let i=state.journeyIndex||0,p=journeyPages[i];journeyContent.innerHTML=`<div class="journey-slide"><div class="journey-emoji">${p.emoji}</div><h3>${p.title}</h3><p>${p.text}</p><small>${i+1} de ${journeyPages.length}</small></div>`;journeyPrev.disabled=i===0;journeyNext.textContent=i===journeyPages.length-1?'Começar 🚀':'Próximo ▶'}
function approve(){
 let s=stats();
 if(!s.complete){
  approval.textContent='A missão ainda não está completa.';
  return;
 }
 if(state.money[today()]){
  approval.textContent='Missão já aprovada hoje.';
  renderAchievements();
  return;
 }
 state.money[today()]=10;
 state.xp=Number(state.xp||0)+10;
 state.piggy=state.piggy||{free:0,saved:0,charity:0};
 state.piggy.free=Number(state.piggy.free||0)+7;
 state.piggy.saved=Number(state.piggy.saved||0)+2;
 state.piggy.charity=Number(state.piggy.charity||0)+1;
 state.aiPlan='';
 save();
 approval.textContent='🦅 Missão aprovada. R$ 10 liberados. +10 XP.';
 renderAll();
 setTimeout(renderAchievements,100);
}
function renderAll(){try{renderMission();renderEagleMessage();renderAnnual();renderCatechism();renderAcademy();renderGradesTable();renderAcademyStats();renderAchievements();renderJourney();weekMoney.textContent=money(weekMoneyTotal());xp.textContent=Number(state.xp||0)+' XP';if(typeof renderBackupStatus==='function')renderBackupStatus();}catch(err){console.error('Erro renderAll V35.2.5:',err);alert('Erro interno: '+err.message);}}
async function runOCR(file){ocrStatus.textContent='Processando arquivo...';let url=URL.createObjectURL(file);reportPreview.innerHTML=file.type.includes('pdf')?`<iframe src="${url}"></iframe>`:`<img src="${url}" alt="Boletim">`;if(file.type.startsWith('image/') && window.Tesseract){ocrStatus.textContent='Lendo imagem com OCR. Isso pode demorar...';let res=await Tesseract.recognize(file,'por+eng');ocrText.value=res.data.text;state.lastOCR=res.data.text;save();ocrStatus.textContent='OCR concluído. Revise o texto e clique em detectar notas.';return}ocrStatus.textContent='Arquivo carregado. Para OCR automático, prefira imagem nítida do boletim.'}
document.addEventListener('change',e=>{if(e.target.matches('#tasks input')){state.checked[e.target.dataset.id]=e.target.checked;state.aiPlan='';save();renderAll()}if(e.target.matches('[data-grade-sub]')){let s=e.target.dataset.gradeSub,i=Number(e.target.dataset.gradeI);state.grades[s][i]=Number(e.target.value||0);save();renderGradesTable();}if(e.target.id==='disciplineSelect'){state.selectedSubject=e.target.value;state.academySession=null;save();renderAcademySession()}if(e.target.id==='reportFile'){let file=e.target.files[0];if(file)runOCR(file)}if(e.target.id==='importGrades'){let file=e.target.files[0];if(!file)return;let r=new FileReader();r.onload=()=>{try{state.grades=JSON.parse(r.result);save();renderGradesTable();alert('Boletim importado.')}catch(e){alert('Arquivo inválido.')}};r.readAsText(file)}});
document.addEventListener('input',e=>{if(e.target.id==='cateSearch')renderCateSearch()});
document.addEventListener('click',e=>{if(e.target.matches('[data-tab]'))switchTab(e.target.dataset.tab);if(e.target.id==='goParent')switchTab('parent');if(e.target.id==='approve')approve();if(e.target.id==='parseGrades'){let found=parseGradesFromText(ocrText.value);let count=applyDetectedGrades(found);parseResult.innerHTML=count?`Notas detectadas e aplicadas: ${count}. Revise a tabela.`:'Nenhuma nota detectada automaticamente. Revise o texto ou preencha manualmente.'}if(e.target.id==='resetQuestionHistory'){state.seenQuestions={};state.academySession=null;save();alert('Histórico reiniciado.')}if(e.target.id==='startAcademySession'){startAcademySession();}if(e.target.id==='smartQuestion'){state.selectedSubject=smartPriority();state.academySession=null;save();renderAcademy();}if(e.target.matches('[data-annual]'))describeDate(e.target.dataset.annual);if(e.target.matches('[data-open-date-cate]')){let key=e.target.dataset.openDateCate;let idx=saturdaysOfYear().findIndex(d=>iso(d)===key);state.catePage=idx>=0?idx:cateWeekIndex(new Date(key+'T00:00:00'));save();switchTab('catechism')}if(e.target.matches('[data-open-cate]')){state.catePage=Number(e.target.dataset.openCate);state.aiPlan='';save();switchTab('catechism')}if(e.target.matches('[data-subject]'))showQuestion(e.target.dataset.subject);if(e.target.matches('.answer-session')){answerAcademySession(e.target.dataset.i);}if(e.target.matches('.answer')){let sub=e.target.dataset.sub,q=questionBank[sub][Number(e.target.dataset.qi)],ok=Number(e.target.dataset.i)===q[2];e.target.classList.add(ok?'correct':'wrong');state.xp+=ok?5:0;state.academyStats[sub]=state.academyStats[sub]||{correct:0,total:0};state.academyStats[sub].total++;if(ok)state.academyStats[sub].correct++;let fb=e.target.parentElement.querySelector('.feedback');fb.classList.remove('hidden');fb.textContent=ok?'✅ Correto! +5 XP':'❌ '+q[3];save();renderAcademyStats();}if(e.target.id==='continueCatechism'){state.catePage=cateWeekIndex();save();switchTab('catechism')}if(e.target.id==='prevCate'){state.catePage=Math.max(0,(state.catePage||0)-1);save();renderAll()}if(e.target.id==='nextCate'){state.catePage=Math.min(51,(state.catePage||0)+1);save();renderAll()}if(e.target.id==='favCate'){let i=state.catePage||0;state.cateFavorites=state.cateFavorites.includes(i)?state.cateFavorites.filter(x=>x!==i):[...state.cateFavorites,i];save();renderAll()}if(e.target.id==='markCate'){let i=state.catePage||0,key=iso(saturdaysOfYear()[i]);if(!state.cateDone[key]){state.cateDone[key]=true;state.cateXP+=10;state.xp+=10;save()}renderAll()}if(e.target.id==='journeyNext'){if(state.journeyIndex<journeyPages.length-1){state.journeyIndex++;save();renderJourney()}else switchTab('today')}if(e.target.id==='journeyPrev'){if(state.journeyIndex>0){state.journeyIndex--;save();renderJourney()}}if(e.target.id==='restartJourney'){state.journeyIndex=0;save();renderJourney()}if(e.target.id==='saveGrades'){save();alert('Notas salvas e sincronizadas com o responsável.')}if(e.target.id==='exportGrades'){let blob=new Blob([JSON.stringify(state.grades,null,2)],{type:'application/json'});let a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download='boletim-projeto-aguia.json';a.click()}if(e.target.id==='export'){let blob=new Blob([JSON.stringify(state,null,2)],{type:'application/json'});let a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download='projeto-aguia-v35-2-4-progresso.json';a.click()}if(e.target.id==='logout'){localStorage.removeItem('unlockedV23');location.reload()}});
/* Service Worker desativado na V35.2.5 para evitar cache quebrado. */
if('serviceWorker' in navigator){navigator.serviceWorker.getRegistrations().then(rs=>rs.forEach(r=>r.unregister())).catch(()=>{});}
renderAll();
setTimeout(renderAchievements,150);
setTimeout(renderAchievements,100);
